} ChatHistory;

ChatHistory *create_shared_history(void);
void add_message(ChatHistory *h, const char *msg);
void print_history(ChatHistory *h);

void test_create_shared_history(void) {
    mq_unlink(SHM_NAME);
    ChatHistory *h = create_shared_history();
    TEST_ASSERT_NOT_NULL(h);
    TEST_ASSERT_EQUAL_INT(0, h->count);
    munmap(h, sizeof(ChatHistory));
    shm_unlink(SHM_NAME);
}

void test_add_message(void) {
    mq_unlink(SHM_NAME);
    ChatHistory *h = create_shared_history();
    add_message(h, "test msg");
    TEST_ASSERT_EQUAL_INT(1, h->count);
    TEST_ASSERT_EQUAL_STRING("test msg", h->messages[0]);
    munmap(h, sizeof(ChatHistory));
    shm_unlink(SHM_NAME);
}

void test_multiple_messages(void) {
    mq_unlink(SHM_NAME);
    ChatHistory *h = create_shared_history();
    add_message(h, "msg1");
    add_message(h, "msg2");
    add_message(h, "msg3");
    TEST_ASSERT_EQUAL_INT(3, h->count);
    TEST_ASSERT_EQUAL_STRING("msg2", h->messages[1]);
    munmap(h, sizeof(ChatHistory));
    shm_unlink(SHM_NAME);
}

int main(void) {
    RUN_TEST(test_create_shared_history);
    RUN_TEST(test_add_message);
    RUN_TEST(test_multiple_messages);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

